<?php
 namespace WPAICG\Vector\Providers\Pinecone\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_Pinecone_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function create_index_if_not_exists_logic(AIPKit_Vector_Pinecone_Strategy $strategyInstance, string $index_name, array $index_config): array|WP_Error { $list_response = list_indexes_logic($strategyInstance); if (!is_wp_error($list_response) && is_array($list_response)) { foreach ($list_response as $existing_index) { if (isset($existing_index['name']) && $existing_index['name'] === $index_name) { return describe_index_logic($strategyInstance, $index_name); } } } $path = '/indexes'; $body = [ 'name' => $index_name, 'dimension' => absint($index_config['dimension'] ?? 1536), 'metric' => strtolower($index_config['metric'] ?? 'cosine'), 'spec' => $index_config['spec'] ?? [ 'serverless' => [ 'cloud' => $index_config['cloud'] ?? 'aws', 'region' => $index_config['region'] ?? 'us-east-1' ] ] ]; if (isset($index_config['deletion_protection'])) $body['deletion_protection'] = $index_config['deletion_protection']; $response = _request_logic($strategyInstance, 'POST', $path, $body); if (is_wp_error($response)) { return $response; } if (is_array($response) && isset($response['name'])) { sleep(15); return describe_index_logic($strategyInstance, $index_name); } return new WP_Error('pinecone_create_unknown_error', __('Unknown error creating Pinecone index.', 'gpt3-ai-content-generator')); }